-- 20260714000000_create_peligros_riesgos_contramedidas.sql
-- Creación de la tabla de catálogo de Peligros, Riesgos, Consecuencias y Contramedidas

CREATE TABLE IF NOT EXISTS public.peligros_riesgos_contramedidas (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    tipo_peligro TEXT NOT NULL,
    peligro TEXT NOT NULL,
    riesgo TEXT NOT NULL,
    consecuencias TEXT NOT NULL,
    medidas_control_administrativas TEXT NOT NULL,
    medidas_control_ingenieria TEXT NOT NULL,
    epps TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- Habilitar Row Level Security (RLS)
ALTER TABLE public.peligros_riesgos_contramedidas ENABLE ROW LEVEL SECURITY;

-- Política de lectura pública para cualquier usuario autenticado o anónimo
CREATE POLICY "Permitir lectura publica de peligros_riesgos_contramedidas" ON public.peligros_riesgos_contramedidas
    FOR SELECT TO public USING (true);

